parameters.jsCode:
const body = $json.body;

const normalized = {
  source_channel: 'webhook',
  customer_name: body.customer?.name ?? '',
  customer_email: body.customer?.email ?? '',
  customer_phone: body.customer?.phone ?? '',
  subject: body.subject ?? '',
  text: body.message ?? '',
  segments: ''
};

return {
  json: normalized
};

const body = $json.body;

const combinedSegments = $json.segments
  .map(segment => `Sprecher ${segment.speaker}: ${segment.text}`)
  .join(" ");

const normalized = {
  source_channel: 'audio',
  customer_name:  '',
  customer_email: '',
  customer_phone: body.phone ?? '',
  subject: '',
  text: combinedSegments ?? '',
  segments: JSON.stringify($json.segments, null, 2)
};

return {
  json: normalized
};

